import {
  Box,
  Button,
  Flex,
  Popover,
  PopoverBody,
  PopoverContent,
  PopoverTrigger,
  Text,
} from "@chakra-ui/react";
import { ReactNode, useState } from "react";

import { useUserInfoQuery } from "../../../hooks/user/queries";
import { ModalLayout } from "../../../modals/Modals";
import { CommentProps } from "../../../types/models/commonTypes";
import { IUser, UserSimpleInfoProps } from "../../../types/models/userTypes/userInfoTypes";
import Avatar from "../../atoms/Avatar";
import UserBadge from "../../atoms/badges/UserBadge";
import Textarea from "../../atoms/Textarea";
import { ChatTalkIcon } from "../../Icons/chatIcons";
import { CrownIcon } from "../../Icons/icons";
import BlurredPart from "../BlurredPart";

export interface IProfileCommentCard {
  user: UserSimpleInfoProps;
  memo?: string;
  leftComponent?: React.ReactNode;
  rightComponent?: React.ReactNode;
  hasCommentButton?: boolean;
  comment?: CommentProps;
  changeComment?: (comment: string) => void;
  size?: "md" | "lg";
  isNoBorder?: boolean;
  crownType?: "main" | "sub";
  isStudy?: boolean;
  pendingType?: "pendingOwner" | "pending" | null;
}

// ...

const STUDY_POPOVER_TEXT = {
  badge: "스터디 출석 횟수",
  subject: "주로 공부하는 과목",
} as const;

const STUDY_STYLE = {
  쉬엄쉬엄: "공부하다가 편하게 대화해도 좋아요!",
  밸런스: "공부할 땐 집중하고, 중간중간 쉬면서 대화하는 걸 좋아해요.",
  몰입형: "적당한 대화도 좋지만, 개인 작업에 더 집중하는 걸 선호해요.",
};

export default function ProfileCommentCard({
  user,
  memo,
  leftComponent,
  rightComponent,
  changeComment,
  hasCommentButton,
  comment,
  isNoBorder,
  crownType,
  isStudy,
  pendingType,
}: IProfileCommentCard) {
  const [isCommentModal, setIsCommentModal] = useState(false);
  const [isEdit, setIsEdit] = useState(false);
  const [text, setText] = useState(comment?.comment || "");

  const { data: userInfo } = useUserInfoQuery();

  const studyUser = user as IUser;

  const changeText = () => {
    changeComment?.(text);
    setIsEdit(false);
    setIsCommentModal(false);
  };

  const closeModal = () => {
    setIsCommentModal(false);
    setIsEdit(false);
  };

  return (
    <>
      <BlurredPart isBlur={pendingType === "pending"} text="참여 승인 대기중...">
        <Flex py={3} align="center" {...(!isNoBorder && { borderBottom: "var(--border)" })}>
          {leftComponent && <Box mr={4}>{leftComponent}</Box>}

          <Flex flex={1} opacity={pendingType === "pendingOwner" ? 0.5 : 1}>
            <Avatar user={user} size="md1" />

            <Flex direction="column" flex={0.95} justify="center" ml={3} my={1}>
              <Flex align="center" mb={memo || comment ? 1 : 0}>
                <Box lineHeight="20px" mr={1} fontWeight="semibold" fontSize="13px">
                  {user?.name || "익명"}
                </Box>

                {!isStudy && <UserBadge badgeIdx={user?.badge?.badgeIdx} />}

                {isStudy && (
                  <>
                    <PlainPopover content="스터디 출석 횟수">
                      <Box as="span" display="inline-flex">
                        <StudyBadge
                          cnt={
                            studyUser?.studyRecord?.accumulationCnt +
                            studyUser?.studyRecord?.accumulationMinutes
                          }
                        />
                      </Box>
                    </PlainPopover>
                    {studyUser?.studyIntroduce?.studyStyle && (
                      <>
                        <StudyPopoverIcon size="md" content={STUDY_POPOVER_TEXT.subject}>
                          <Box fontSize="9px" px={1.5} fontWeight={600}>
                            {studyUser?.studyIntroduce?.subject}
                          </Box>
                        </StudyPopoverIcon>

                        <StudyPopoverIcon
                          size="md2"
                          content={
                            STUDY_STYLE?.[
                              studyUser?.studyIntroduce?.studyStyle
                                ?.split(" ")?.[0]
                                ?.replace(/^\[|\]$/g, "")
                            ]
                          }
                        >
                          <Box fontSize="9px" px={1.5} fontWeight={600}>
                            {studyUser?.studyIntroduce?.studyStyle
                              ?.split(" ")?.[0]
                              ?.replace(/^\[|\]$/g, "")}
                          </Box>
                        </StudyPopoverIcon>
                      </>
                    )}
                  </>
                )}

                {crownType && (
                  <Flex justify="center" align="center" ml={1}>
                    <CrownIcon color={crownType === "main" ? "yellow" : "gray"} />
                  </Flex>
                )}

                {false && (
                  <Button ml={1} variant="unstyled" onClick={() => setIsCommentModal(true)}>
                    <ChatTalkIcon isActive={!!comment} />
                  </Button>
                )}
              </Flex>

              <Flex lineHeight="16px" alignItems="center" color="gray.500" fontSize="12px">
                <Text as="span" noOfLines={1} color="gray.500" fontSize="12px" lineHeight="16px">
                  {text || memo || "코멘트 없음"}
                </Text>

                {user.uid === userInfo?.uid && hasCommentButton && (
                  <Button variant="unstyled" ml={1} onClick={() => setIsCommentModal(true)}>
                    <EditIcon2 />
                  </Button>
                )}
              </Flex>
            </Flex>
          </Flex>

          <Box ml="auto">{rightComponent}</Box>
        </Flex>
      </BlurredPart>

      {isCommentModal && (
        <ModalLayout
          footerOptions={{
            main: {
              text: isEdit ? (comment?.comment ? "변 경" : "입 력") : "확 인",
              func: isEdit ? changeText : closeModal,
            },
            ...(isEdit && { sub: { func: closeModal } }),
            isFull: false,
          }}
          setIsModal={setIsCommentModal}
          title="출석 메세지로 서로 알아봐요!"
        >
          {!isEdit ? (
            <Box
              border="var(--border)"
              textAlign="start"
              p={2}
              borderRadius="12px"
              w="full"
              h="full"
              color="gray.500"
            >
              {comment?.comment || "미작성"}

              {user.uid === userInfo?.uid && (
                <Button ml={2} variant="unstyled" onClick={() => setIsEdit(true)}>
                  <Box mb="2px">
                    <EditIcon />
                  </Box>
                </Button>
              )}
            </Box>
          ) : (
            <Textarea defaultValue={comment?.comment} onChange={(e) => setText(e.target.value)} />
          )}
        </ModalLayout>
      )}
    </>
  );
}
type PlainPopoverProps = {
  children: ReactNode;
  content: ReactNode;
};

function PlainPopover({ children, content }: PlainPopoverProps) {
  return (
    <Popover>
      <PopoverTrigger>{children}</PopoverTrigger>
      <PopoverContent
        textAlign="center"
        fontSize="12px"
        _focus={{ outline: "none", boxShadow: "none" }}
        width="max-content"
      >
        <PopoverBody
          fontSize="11px"
          border="var(--border)"
          borderRadius="4px"
          bg="gray.700"
          borderColor="gray.300"
          fontWeight={400}
          color="white"
          py={1}
          px={2}
        >
          {content}
        </PopoverBody>
      </PopoverContent>
    </Popover>
  );
}

type StudyPopoverIconProps = {
  children: ReactNode;
  content: ReactNode;
  size: "sm" | "md" | "sm2" | "md2";
};

function StudyPopoverIcon({ children, content, size: sizeType }: StudyPopoverIconProps) {
  const size = sizeType === "sm2" ? "sm" : sizeType === "md2" ? "md" : sizeType;

  return (
    <Popover>
      <PopoverTrigger>
        <Flex
          ml={1}
          align="center"
          h="20px"
          borderRadius={size === "sm" ? "full" : "8px"}
          bg={
            sizeType === "md2" || sizeType === "sm2"
              ? "orange.50"
              : size === "sm"
              ? "blue.50"
              : "green.50"
          }
        >
          {children}
        </Flex>
      </PopoverTrigger>

      <PopoverContent
        textAlign="center"
        fontSize="12px"
        _focus={{ outline: "none", boxShadow: "none" }}
        width="max-content"
      >
        <PopoverBody
          fontSize="11px"
          border="var(--border)"
          borderRadius="4px"
          bg="gray.700"
          borderColor="gray.300"
          fontWeight={400}
          color="white"
          py={1}
          px={2}
        >
          {content}
        </PopoverBody>
      </PopoverContent>
    </Popover>
  );
}

export function StudyBadge({ cnt }: { cnt: number }) {
  return (
    <Flex
      ml={1}
      fontWeight={600}
      fontSize="9px"
      h="20px"
      bg="red.50"
      pl={1}
      pr={1.5}
      py="1px"
      borderRadius="8px"
      justify="center"
      align="center"
      color="gray.800"
    >
      🔥{cnt}
    </Flex>
  );
}

